INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, challenge_only, created_at, updated_at)
VALUES ('3d41f638-d67a-4365-b1ac-d7caf4f4e108', 'Which choice best states the main idea of the text?', 'Within historical epistemology, the migration of a metaphor across disciplines has long been read as straightforward progress, a reading that a network of amateurs—whose archives, only recently catalogued, complicate the received chronology—did much to entrench. What that account treats as periodization, however, the persistent residue reframes: the apparent advance, far from being intrinsic, was conditioned by an institutional anachronism that the standard narrative cannot model. Granting that the correlation is genuine, one must still resist the inference that it is causal, for the same configuration recurs though never once the governing parameter is relaxed.', 'passage', '[{"id":"A","text":"Read as a whole, the passage advances a qualified central claim. The opening impression of straightforward progress is, in fact, the passage''s settled thesis —as the nested concession ultimately reveals.","is_correct":false,"explanation":"[False Lead] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"B","text":"Read as a whole, the passage advances a qualified central claim. Because the pattern is causal, the institutional condition it produces must be its effect rather than its source —as the nested concession ultimately reveals.","is_correct":false,"explanation":"[Reciprocal Error] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"C","text":"Read as a whole, the passage advances a qualified central claim. No correlation of this kind can ever, in any field, license a causal inference —as the nested concession ultimately reveals.","is_correct":false,"explanation":"[Over-Extrapolation] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"D","text":"Read as a whole, the passage advances a qualified central claim. A documented correlation is real but not causal, since the same pattern recurs where the supposed mechanism is absent —as the nested concession ultimately reveals.","is_correct":true,"explanation":"Correct: its second sentence is the only one that satisfies the discriminating condition."}]'::jsonb, 'D', 'Logical Reconstruction:
Step 1: The opening sentence is a False Lead: the view the author complicates.
Step 2: The middle concedes the correlation is genuine.
Step 3: The final clause draws the non-obvious implication: genuine but non-causal.
Step 4: The thesis is the synthesis of concession and implication, not any single sentence.

Key Explanation: Choice D is the only option whose second sentence survives the discriminating step above; the others are grounded in real passage language but fail a specific qualifier.

Distractor Analysis:
- Choice A [False Lead]: a 720–740 student is drawn to its accurate first sentence, but its second sentence imports a relationship the passage withholds — exactly the habit this trap exploits.
- Choice B [Reciprocal Error]: a 720–740 student is drawn to its accurate first sentence, but its second sentence satisfies only part of the stated condition — exactly the habit this trap exploits.
- Choice C [Over-Extrapolation]: a 720–740 student is drawn to its accurate first sentence, but its second sentence extends beyond the passage''s qualifiers — exactly the habit this trap exploits.

Difficulty Justification: This item is Challenge-tier because of False-Lead architecture requiring synthesis of a mid-passage concession with a counter-intuitive final structural implication.

Score Prediction: A student scoring 750+ on DSAT R&W should answer this item correctly with deliberate reasoning; a student scoring 720–740 should find it genuinely difficult even after a careful first pass.', NULL, 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"dsat_blueprint_v1":true,"tier":"challenge","challenge_tier":true,"challenged_problem":true,"difficulty_tier":"challenge","explanation_v2":true,"generator":"generate-challenge-bank.mjs","rw_subtype":"main_idea","rw_format":"passage_mc","challenge_key":"CID"}'::jsonb, true, now(), now());
