(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, challenge_only, created_at, updated_at)
VALUES ('96ba2cc3-9c78-4b3e-8656-e54af93c55a4', 'Which choice best states the main idea of the text?', 'Within cognitive neuroscience, the reappraisal of a marginal archive has long been read as straightforward progress, a reading that a circle of self-taught practitioners—whose archives, only recently catalogued, complicate the received chronology—did much to entrench. What that account treats as predictive coding, however, the measured asymmetry reframes: the apparent advance, far from being intrinsic, was conditioned by an institutional metaplasticity that the standard narrative cannot model. Granting that the correlation is genuine, one must still resist the inference that it is causal, for the same configuration recurs though never once the governing parameter is relaxed.', 'passage', '[{"id":"A","text":"Read as a whole, the passage advances a qualified central claim. A documented correlation is real but not causal, since the same pattern recurs where the supposed mechanism is absent —as the evidence, read in full, requires.","is_correct":true,"explanation":"Correct: its second sentence is the only one that satisfies the discriminating condition."},{"id":"B","text":"Read as a whole, the passage advances a qualified central claim. The opening impression of straightforward progress is, in fact, the passage''s settled thesis —as the evidence, read in full, requires.","is_correct":false,"explanation":"[False Lead] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"C","text":"Read as a whole, the passage advances a qualified central claim. Because the pattern is causal, the institutional condition it produces must be its effect rather than its source —as the evidence, read in full, requires.","is_correct":false,"explanation":"[Reciprocal Error] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"D","text":"Read as a whole, the passage advances a qualified central claim. No correlation of this kind can ever, in any field, license a causal inference —as the evidence, read in full, requires.","is_correct":false,"explanation":"[Over-Extrapolation] Grounded in passage language but fails on a specific qualifier in its second sentence."}]'::jsonb, 'A', 'Logical Reconstruction:
Step 1: The opening sentence is a False Lead: the view the author complicates.
Step 2: The middle concedes the correlation is genuine.
Step 3: The final clause draws the non-obvious implication: genuine but non-causal.
Step 4: The thesis is the synthesis of concession and implication, not any single sentence.

Key Explanation: Choice A is the only option whose second sentence survives the discriminating step above; the others are grounded in real passage language but fail a specific qualifier.

Distractor Analysis:
- Choice B [False Lead]: a 720–740 student is drawn to its accurate first sentence, but its second sentence imports a relationship the passage withholds — exactly the habit this trap exploits.
- Choice C [Reciprocal Error]: a 720–740 student is drawn to its accurate first sentence, but its second sentence satisfies only part of the stated condition — exactly the habit this trap exploits.
- Choice D [Over-Extrapolation]: a 720–740 student is drawn to its accurate first sentence, but its second sentence extends beyond the passage''s qualifiers — exactly the habit this trap exploits.

Difficulty Justification: This item is Challenge-tier because of False-Lead architecture requiring synthesis of a mid-passage concession with a counter-intuitive final structural implication.

Score Prediction: A student scoring 750+ on DSAT R&W should answer this item correctly with deliberate reasoning; a student scoring 720–740 should find it genuinely difficult even after a careful first pass.', NULL, 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"dsat_blueprint_v1":true,"tier":"challenge","challenge_tier":true,"challenged_problem":true,"difficulty_tier":"challenge","explanation_v2":true,"generator":"generate-challenge-bank.mjs","rw_subtype":"main_idea","rw_format":"passage_mc","challenge_key":"CID"}'::jsonb, true, now(), now());
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, challenge_only, created_at, updated_at)
VALUES ('f71da969-92b0-4f44-a7af-823c33153f98', 'Which finding, if true, would most directly support the team''s full hypothesis?', 'A research team in cognitive neuroscience hypothesizes that intervention A raises outcome B, but only when context C is active and only when baseline parameter D remains below a threshold of 50 units; when D exceeds 50, the relationship is predicted to invert regardless of C. The team seeks the single observation that would confirm the full conditional rather than any part of it.', 'passage', '[{"id":"A","text":"In a trial with C active and D at 42 units, A was applied. Outcome B rose, and a paired trial with D above threshold showed B falling — confirming both the primary case and the inversion —as the evidence, read in full, requires.","is_correct":true,"explanation":"Correct: its second sentence is the only one that satisfies the discriminating condition."},{"id":"B","text":"In a trial with C active and D at 62 units, A was applied. Outcome B fell, which violates the primary case because D exceeded the stated threshold —as the evidence, read in full, requires, as the argument is staged.","is_correct":false,"explanation":"[Under-Specification] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"C","text":"In a trial with C inactive and D at 40 units, A was applied. Outcome B did not rise, which is uninformative because context C was not active —as the evidence, read in full, requires, given the stated qualifiers.","is_correct":false,"explanation":"[Under-Specification] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"D","text":"In a trial in which A was withheld entirely, the team measured B. B was unchanged, which tests a different relationship than the hypothesis specifies —as the evidence, read in full, requires, on the evidence presented.","is_correct":false,"explanation":"[True-But-Irrelevant] Grounded in passage language but fails on a specific qualifier in its second sentence."}]'::jsonb, 'A', 'Logical Reconstruction:
Step 1: List the conditions: A raises B only if C active AND D below T; above T it inverts.
Step 2: A correct finding must verify the primary case AND the inversion together.
Step 3: Eliminate findings that satisfy only one dependency or test A''s absence.
Step 4: Only the paired observation across the threshold confirms the full conditional.

Key Explanation: Choice A is the only option whose second sentence survives the discriminating step above; the others are grounded in real passage language but fail a specific qualifier.

Distractor Analysis:
- Choice B [Under-Specification]: a 720–740 student is drawn to its accurate first sentence, but its second sentence imports a relationship the passage withholds — exactly the habit this trap exploits.
- Choice C [Under-Specification]: a 720–740 student is drawn to its accurate first sentence, but its second sentence satisfies only part of the stated condition — exactly the habit this trap exploits.
- Choice D [True-But-Irrelevant]: a 720–740 student is drawn to its accurate first sentence, but its second sentence extends beyond the passage''s qualifiers — exactly the habit this trap exploits.

Difficulty Justification: This item is Challenge-tier because of double-conditional hypothesis with an interactive variable and a baseline-threshold inversion case.

Score Prediction: A student scoring 750+ on DSAT R&W should answer this item correctly with deliberate reasoning; a student scoring 720–740 should find it genuinely difficult even after a careful first pass.', NULL, 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"dsat_blueprint_v1":true,"tier":"challenge","challenge_tier":true,"challenged_problem":true,"difficulty_tier":"challenge","explanation_v2":true,"generator":"generate-challenge-bank.mjs","rw_subtype":"textual_evidence","rw_format":"passage_mc","challenge_key":"COE_T"}'::jsonb, true, now(), now());
